const sector = $('Course Input Form').first().json['Sector'];
const topic = $('Course Input Form').first().json['Course Topic'];
const level = $('Course Input Form').first().json['WSQ Level'];
const context = $('Course Input Form').first().json['Additional Context'] || '';

const tscData = $input.first().json;
const sectorTSCs = tscData.sectors[sector] || [];
if (sectorTSCs.length === 0) {
  return [{ json: { error: 'No TSC data found for sector: ' + sector } }];
}

const keywords = topic.toLowerCase()
  .split(/[\\s,;/&+]+/)
  .filter(w => w.length > 2)
  .filter(w => !['and', 'the', 'for', 'with', 'using', 'from', 'into'].includes(w));

const scored = sectorTSCs.map(tsc => {
  const skillText = (tsc.skill + ' ' + (tsc.parent || '')).toLowerCase();
  const kaText = [...(tsc.knowledge || []), ...(tsc.abilities || [])].join(' ').toLowerCase();
  const skillMatches = keywords.filter(kw => skillText.includes(kw));
  const kaMatches = keywords.filter(kw => kaText.includes(kw));
  const score = skillMatches.length * 3 + kaMatches.length;
  return { ...tsc, score, matchedKeywords: [...new Set([...skillMatches, ...kaMatches])] };
}).filter(tsc => tsc.score > 0)
  .sort((a, b) => b.score - a.score);

const topMatches = scored.slice(0, 8);
const results = topMatches.length > 0 ? topMatches : sectorTSCs.slice(0, 5);
const ccsResults = (tscData.ccs || []).slice(0, 3);

return [{
  json: {
    sector, topic, level, context,
    matched_tscs: results.map(tsc => ({
      tsc_code: tsc.code, skill_name: tsc.skill, proficiency_level: tsc.level,
      emerging_skill: tsc.emerging, matched_keywords: tsc.matchedKeywords || [],
      knowledge_statements: tsc.knowledge || [], ability_statements: tsc.abilities || []
    })),
    matched_ccs: ccsResults.map(ccs => ({
      ccs_code: ccs.code, skill_name: ccs.skill,
      knowledge_statements: ccs.knowledge || [], ability_statements: ccs.abilities || []
    })),
    total_sector_tscs: sectorTSCs.length,
    keyword_matches_found: topMatches.length
  }
}];

